import type { Context } from "hono"

import consola from "consola"
import { streamSSE, type SSEMessage } from "hono/streaming"

import { awaitApproval } from "~/lib/approval"
import { resolveEndpoint } from "~/lib/endpoint-routing"
import { checkRateLimit } from "~/lib/rate-limit"
import { state } from "~/lib/state"
import { getTokenCount } from "~/lib/tokenizer"
import { isNullish } from "~/lib/utils"
import { openaiToAnthropicPayload } from "~/routes/messages/non-stream-translation"
import {
  createChatCompletions,
  type ChatCompletionResponse,
  type ChatCompletionsPayload,
} from "~/services/copilot/create-chat-completions"
import {
  createResponses,
  createResponsesStreamState,
  translateResponsesStreamEvent,
} from "~/services/copilot/create-responses"
import {
  forwardNativeMessagesNonStreaming,
  forwardNativeMessagesStreaming,
} from "~/services/copilot/forward-native-messages"

export async function handleCompletion(c: Context) {
  await checkRateLimit(state)

  let payload = await c.req.json<ChatCompletionsPayload>()
  consola.debug("Request payload:", JSON.stringify(payload).slice(-400))

  // Find the selected model
  const selectedModel = state.models?.data.find(
    (model) => model.id === payload.model,
  )

  // Calculate and display token count
  try {
    if (selectedModel) {
      const tokenCount = await getTokenCount(payload, selectedModel)
      consola.info("Current token count:", tokenCount)
    } else {
      consola.warn("No model selected, skipping token count calculation")
    }
  } catch (error) {
    consola.warn("Failed to calculate token count:", error)
  }

  if (state.manualApprove) await awaitApproval()

  if (isNullish(payload.max_tokens)) {
    payload = {
      ...payload,
      max_tokens: selectedModel?.capabilities.limits.max_output_tokens,
    }
    consola.debug("Set max_tokens to:", JSON.stringify(payload.max_tokens))
  }

  const endpoint = resolveEndpoint(payload.model, state.models)
  const signal = c.req.raw.signal

  // Reroute Claude models to native /v1/messages passthrough
  // Claude on /chat/completions loses tool calling and other native features
  if (endpoint === "/v1/messages") {
    consola.debug(
      `Rerouting Claude model ${payload.model} to native /v1/messages`,
    )
    return handleNativeReroute(c, payload)
  }

  // Route to /responses for GPT-5.x and models that only support it
  if (endpoint === "/responses") {
    consola.debug(`Using /responses endpoint for model: ${payload.model}`)
    return handleResponsesEndpoint(c, payload, signal)
  }

  // Existing /chat/completions path
  const response = await createChatCompletions(payload, signal)

  if (isNonStreaming(response)) {
    consola.debug("Non-streaming response:", JSON.stringify(response))
    return c.json(response)
  }

  consola.debug("Streaming response")
  return streamSSE(c, async (stream) => {
    try {
      for await (const chunk of response) {
        consola.debug("Streaming chunk:", JSON.stringify(chunk))
        await stream.writeSSE(chunk as SSEMessage)
      }
    } catch (err) {
      if (
        signal.aborted
        || (err instanceof Error && err.name === "AbortError")
      ) {
        consola.debug("chat-completions stream aborted by client")
        return
      }
      throw err
    }
  })
}

async function handleResponsesEndpoint(
  c: Context,
  payload: ChatCompletionsPayload,
  signal?: AbortSignal,
) {
  const response = await createResponses(payload, signal)

  if (isNonStreaming(response)) {
    consola.debug("Non-streaming /responses result:", JSON.stringify(response))
    return c.json(response)
  }

  consola.debug("Streaming /responses response")
  return streamSSE(c, async (stream) => {
    const streamState = createResponsesStreamState()

    try {
      for await (const rawEvent of response) {
        if (!rawEvent.data || rawEvent.data === "[DONE]") continue

        const parsed = JSON.parse(rawEvent.data) as Record<string, unknown>
        const eventType =
          rawEvent.event ?? (parsed.type as string | undefined) ?? ""

        const chunks = translateResponsesStreamEvent(
          { event: eventType, data: parsed },
          streamState,
        )

        for (const chunk of chunks) {
          consola.debug("Translated /responses chunk:", JSON.stringify(chunk))
          await stream.writeSSE({
            data: JSON.stringify(chunk),
          })
        }
      }
    } catch (err) {
      if (
        signal?.aborted
        || (err instanceof Error && err.name === "AbortError")
      ) {
        consola.debug("/responses stream aborted by client")
        return
      }
      throw err
    }
  })
}

const isNonStreaming = (
  response: Awaited<ReturnType<typeof createChatCompletions>>,
): response is ChatCompletionResponse => Object.hasOwn(response, "choices")

/**
 * Reroute a /chat/completions request for a Claude model through
 * native /v1/messages passthrough. Translates OpenAI→Anthropic,
 * forwards natively, translates Anthropic→OpenAI back.
 */
async function handleNativeReroute(
  c: Context,
  payload: ChatCompletionsPayload,
) {
  const anthropicPayload = openaiToAnthropicPayload(payload)

  if (!payload.stream) {
    const response = await forwardNativeMessagesNonStreaming(anthropicPayload)
    return c.json(
      anthropicResponseToOpenAI(response as Record<string, unknown>),
    )
  }

  return streamSSE(c, async (stream) => {
    for await (const event of forwardNativeMessagesStreaming(
      anthropicPayload,
    )) {
      // Translate Anthropic SSE events to OpenAI chunks
      const chunk = anthropicEventToOpenAIChunk(event)
      if (chunk) {
        await stream.writeSSE({
          data: JSON.stringify(chunk),
        })
      }
    }
  })
}

/**
 * Convert Anthropic stop_reason to OpenAI finish_reason.
 */
function mapAnthropicFinishReason(
  stopReason: string | null | undefined,
): "stop" | "length" | "tool_calls" | "content_filter" {
  if (stopReason === "tool_use") return "tool_calls"
  if (stopReason === "max_tokens") return "length"
  return "stop"
}

/**
 * Extract text and tool calls from Anthropic content blocks.
 */
function extractAnthropicContent(
  content: Array<{
    type: string
    text?: string
    id?: string
    name?: string
    input?: unknown
  }>,
): {
  text: string
  toolCalls: Array<{
    id: string
    type: "function"
    function: { name: string; arguments: string }
  }>
} {
  let text = ""
  const toolCalls: Array<{
    id: string
    type: "function"
    function: { name: string; arguments: string }
  }> = []

  for (const block of content) {
    if (block.type === "text" && block.text) {
      text += block.text
    } else if (block.type === "tool_use" && block.name && block.id) {
      toolCalls.push({
        id: block.id,
        type: "function",
        function: {
          name: block.name,
          arguments: JSON.stringify(block.input ?? {}),
        },
      })
    }
  }

  return { text, toolCalls }
}

/**
 * Convert a raw Anthropic Messages response to OpenAI Chat Completion format.
 */
function anthropicResponseToOpenAI(
  resp: Record<string, unknown>,
): ChatCompletionResponse {
  const rawContent = resp.content as
    | Array<{
        type: string
        text?: string
        id?: string
        name?: string
        input?: unknown
      }>
    | undefined
  const content = rawContent ?? []
  const { text, toolCalls } = extractAnthropicContent(content)
  const finishReason = mapAnthropicFinishReason(
    resp.stop_reason as string | null,
  )
  const rawUsage = resp.usage as
    | { input_tokens: number; output_tokens: number }
    | undefined
  const usage =
    rawUsage ?
      {
        prompt_tokens: rawUsage.input_tokens,
        completion_tokens: rawUsage.output_tokens,
        total_tokens: rawUsage.input_tokens + rawUsage.output_tokens,
      }
    : undefined

  return {
    id: typeof resp.id === "string" ? resp.id : "",
    object: "chat.completion",
    created: Math.floor(Date.now() / 1000),
    model: typeof resp.model === "string" ? resp.model : "",
    choices: [
      {
        index: 0,
        message: {
          role: "assistant",
          content: text || null,
          ...(toolCalls.length > 0 ? { tool_calls: toolCalls } : {}),
        },
        logprobs: null,
        finish_reason: finishReason,
      },
    ],
    usage,
  }
}

/**
 * Convert an Anthropic SSE event to an OpenAI streaming chunk.
 */
function anthropicEventToOpenAIChunk(event: {
  type: string
  data: Record<string, unknown>
}): Record<string, unknown> | null {
  const { type, data } = event

  if (type === "content_block_delta") {
    const delta = data.delta as { type: string; text?: string } | undefined
    if (delta?.type === "text_delta" && delta.text) {
      return {
        object: "chat.completion.chunk",
        choices: [
          { index: 0, delta: { content: delta.text }, finish_reason: null },
        ],
      }
    }
  }

  if (type === "message_delta") {
    const delta = data.delta as Record<string, unknown> | undefined
    const stopReason = delta?.stop_reason as string | undefined
    if (stopReason) {
      return {
        object: "chat.completion.chunk",
        choices: [
          {
            index: 0,
            delta: {},
            finish_reason: mapAnthropicFinishReason(stopReason),
          },
        ],
      }
    }
  }

  return null
}

import { badRequest } from "~/lib/error"
import {
  anthropicToCopilotModelId,
  copilotToAnthropicModelId,
} from "~/lib/model-mapping"
import { state } from "~/lib/state"
import {
  type ChatCompletionResponse,
  type ChatCompletionsPayload,
  type ContentPart,
  type Message,
  type TextPart,
  type Tool,
  type ToolCall,
} from "~/services/copilot/create-chat-completions"

import {
  type AnthropicAssistantContentBlock,
  type AnthropicAssistantMessage,
  type AnthropicMessage,
  type AnthropicMessagesPayload,
  type AnthropicResponse,
  type AnthropicTextBlock,
  type AnthropicThinkingBlock,
  type AnthropicTool,
  type AnthropicToolResultBlock,
  type AnthropicToolUseBlock,
  type AnthropicUserContentBlock,
  type AnthropicUserMessage,
} from "./anthropic-types"
import { mapOpenAIStopReasonToAnthropic } from "./utils"

// Payload translation

export function translateToOpenAI(
  payload: AnthropicMessagesPayload,
): ChatCompletionsPayload {
  return {
    model: translateModelName(payload.model),
    messages: translateAnthropicMessagesToOpenAI(
      payload.messages,
      payload.system,
    ),
    max_tokens: payload.max_tokens,
    stop: payload.stop_sequences,
    stream: payload.stream,
    temperature: payload.temperature,
    top_p: payload.top_p,
    user: payload.metadata?.user_id,
    tools: translateAnthropicToolsToOpenAI(payload.tools),
    tool_choice: translateAnthropicToolChoiceToOpenAI(payload.tool_choice),
  }
}

function translateModelName(model: string): string {
  return anthropicToCopilotModelId(model, state.is1MContext)
}

function translateAnthropicMessagesToOpenAI(
  anthropicMessages: Array<AnthropicMessage>,
  system: string | Array<AnthropicTextBlock> | undefined,
): Array<Message> {
  const systemMessages = handleSystemPrompt(system)

  const otherMessages = anthropicMessages.flatMap((message) =>
    message.role === "user" ?
      handleUserMessage(message)
    : handleAssistantMessage(message),
  )

  return [...systemMessages, ...otherMessages]
}

function handleSystemPrompt(
  system: string | Array<AnthropicTextBlock> | undefined,
): Array<Message> {
  if (!system) {
    return []
  }

  if (typeof system === "string") {
    return [{ role: "system", content: system }]
  } else {
    const systemText = system.map((block) => block.text).join("\n\n")
    return [{ role: "system", content: systemText }]
  }
}

function handleUserMessage(message: AnthropicUserMessage): Array<Message> {
  const newMessages: Array<Message> = []

  if (Array.isArray(message.content)) {
    const toolResultBlocks = message.content.filter(
      (block): block is AnthropicToolResultBlock =>
        block.type === "tool_result",
    )
    const otherBlocks = message.content.filter(
      (block) => block.type !== "tool_result",
    )

    // Tool results must come first to maintain protocol: tool_use -> tool_result -> user
    for (const block of toolResultBlocks) {
      if (!block.tool_use_id || !block.tool_use_id.trim()) {
        throw badRequest("tool_result block is missing tool_use_id")
      }
      newMessages.push({
        role: "tool",
        tool_call_id: block.tool_use_id,
        content: mapContent(block.content),
      })
    }

    if (otherBlocks.length > 0) {
      newMessages.push({
        role: "user",
        content: mapContent(otherBlocks),
      })
    }
  } else {
    newMessages.push({
      role: "user",
      content: mapContent(message.content),
    })
  }

  return newMessages
}

function handleAssistantMessage(
  message: AnthropicAssistantMessage,
): Array<Message> {
  if (!Array.isArray(message.content)) {
    return [
      {
        role: "assistant",
        content: mapContent(message.content),
      },
    ]
  }

  const toolUseBlocks = message.content.filter(
    (block): block is AnthropicToolUseBlock => block.type === "tool_use",
  )

  const textBlocks = message.content.filter(
    (block): block is AnthropicTextBlock => block.type === "text",
  )

  const thinkingBlocks = message.content.filter(
    (block): block is AnthropicThinkingBlock => block.type === "thinking",
  )

  // Combine text and thinking blocks, as OpenAI doesn't have separate thinking blocks
  const allTextContent = [
    ...textBlocks.map((b) => b.text),
    ...thinkingBlocks.map((b) => b.thinking),
  ].join("\n\n")

  return toolUseBlocks.length > 0 ?
      [
        {
          role: "assistant",
          content: allTextContent || null,
          tool_calls: toolUseBlocks.map((toolUse) => ({
            id: toolUse.id,
            type: "function",
            function: {
              name: toolUse.name,
              arguments: JSON.stringify(toolUse.input),
            },
          })),
        },
      ]
    : [
        {
          role: "assistant",
          content: mapContent(message.content),
        },
      ]
}

function mapContent(
  content:
    | string
    | Array<AnthropicUserContentBlock | AnthropicAssistantContentBlock>,
): string | Array<ContentPart> | null {
  if (typeof content === "string") {
    return content
  }
  if (!Array.isArray(content)) {
    return null
  }

  const hasImage = content.some((block) => block.type === "image")
  if (!hasImage) {
    return content
      .filter(
        (block): block is AnthropicTextBlock | AnthropicThinkingBlock =>
          block.type === "text" || block.type === "thinking",
      )
      .map((block) => (block.type === "text" ? block.text : block.thinking))
      .join("\n\n")
  }

  const contentParts: Array<ContentPart> = []
  for (const block of content) {
    switch (block.type) {
      case "text": {
        contentParts.push({ type: "text", text: block.text })

        break
      }
      case "thinking": {
        contentParts.push({ type: "text", text: block.thinking })

        break
      }
      case "image": {
        contentParts.push({
          type: "image_url",
          image_url: {
            url: `data:${block.source.media_type};base64,${block.source.data}`,
          },
        })

        break
      }
      // No default
    }
  }
  return contentParts
}

function translateAnthropicToolsToOpenAI(
  anthropicTools: Array<AnthropicTool> | undefined,
): Array<Tool> | undefined {
  if (!anthropicTools) {
    return undefined
  }
  return anthropicTools.map((tool) => ({
    type: "function",
    function: {
      name: tool.name,
      description: tool.description,
      parameters: tool.input_schema,
    },
  }))
}

function translateAnthropicToolChoiceToOpenAI(
  anthropicToolChoice: AnthropicMessagesPayload["tool_choice"],
): ChatCompletionsPayload["tool_choice"] {
  if (!anthropicToolChoice) {
    return undefined
  }

  switch (anthropicToolChoice.type) {
    case "auto": {
      return "auto"
    }
    case "any": {
      return "required"
    }
    case "tool": {
      if (anthropicToolChoice.name) {
        return {
          type: "function",
          function: { name: anthropicToolChoice.name },
        }
      }
      return undefined
    }
    case "none": {
      return "none"
    }
    default: {
      return undefined
    }
  }
}

// Response translation

function getThinkingBlocks(
  reasoningText: string | null | undefined,
): Array<AnthropicThinkingBlock> {
  if (!reasoningText) return []
  return [{ type: "thinking", thinking: reasoningText }]
}

export function translateToAnthropic(
  response: ChatCompletionResponse,
): AnthropicResponse {
  // Merge content from all choices
  const allTextBlocks: Array<AnthropicTextBlock> = []
  const allToolUseBlocks: Array<AnthropicToolUseBlock> = []
  const allThinkingBlocks: Array<AnthropicThinkingBlock> = []
  let stopReason: "stop" | "length" | "tool_calls" | "content_filter" | null =
    null // default
  stopReason = response.choices[0]?.finish_reason ?? stopReason

  // Process all choices to extract text and tool use blocks
  for (const choice of response.choices) {
    const textBlocks = getAnthropicTextBlocks(choice.message.content)
    const toolUseBlocks = getAnthropicToolUseBlocks(choice.message.tool_calls)

    // Map reasoning_text from GPT-5.x /responses to Anthropic thinking blocks
    allThinkingBlocks.push(...getThinkingBlocks(choice.message.reasoning_text))

    allTextBlocks.push(...textBlocks)
    allToolUseBlocks.push(...toolUseBlocks)

    // Use the finish_reason from the first choice, or prioritize tool_calls
    if (choice.finish_reason === "tool_calls" || stopReason === "stop") {
      stopReason = choice.finish_reason
    }
  }

  return {
    id: response.id,
    type: "message",
    role: "assistant",
    model: copilotToAnthropicModelId(response.model),
    content: [...allThinkingBlocks, ...allTextBlocks, ...allToolUseBlocks],
    stop_reason: mapOpenAIStopReasonToAnthropic(stopReason),
    stop_sequence: null,
    usage: {
      input_tokens:
        (response.usage?.prompt_tokens ?? 0)
        - (response.usage?.prompt_tokens_details?.cached_tokens ?? 0),
      output_tokens: response.usage?.completion_tokens ?? 0,
      ...(response.usage?.prompt_tokens_details?.cached_tokens
        !== undefined && {
        cache_read_input_tokens:
          response.usage.prompt_tokens_details.cached_tokens,
      }),
    },
  }
}

function getAnthropicTextBlocks(
  messageContent: Message["content"],
): Array<AnthropicTextBlock> {
  if (typeof messageContent === "string") {
    return [{ type: "text", text: messageContent }]
  }

  if (Array.isArray(messageContent)) {
    return messageContent
      .filter((part): part is TextPart => part.type === "text")
      .map((part) => ({ type: "text", text: part.text }))
  }

  return []
}

function getAnthropicToolUseBlocks(
  toolCalls: Array<ToolCall> | undefined,
): Array<AnthropicToolUseBlock> {
  if (!toolCalls) {
    return []
  }
  return toolCalls.map((toolCall) => ({
    type: "tool_use",
    id: toolCall.id,
    name: toolCall.function.name,
    input: JSON.parse(toolCall.function.arguments) as Record<string, unknown>,
  }))
}

/**
 * Convert an OpenAI assistant message to Anthropic content blocks.
 */
function convertAssistantMessage(
  msg: ChatCompletionsPayload["messages"][0],
): AnthropicMessage {
  const blocks: Array<AnthropicAssistantContentBlock> = []
  if (msg.content) {
    const text = typeof msg.content === "string" ? msg.content : ""
    if (text) blocks.push({ type: "text", text })
  }
  if (msg.tool_calls) {
    for (const tc of msg.tool_calls) {
      blocks.push({
        type: "tool_use",
        id: tc.id,
        name: tc.function.name,
        input: JSON.parse(tc.function.arguments) as Record<string, unknown>,
      })
    }
  }
  if (blocks.length > 0) {
    return { role: "assistant", content: blocks } as AnthropicMessage
  }
  const fallbackContent = typeof msg.content === "string" ? msg.content : ""
  return { role: "assistant", content: fallbackContent } as AnthropicMessage
}

/**
 * Convert OpenAI messages to Anthropic messages, extracting system prompt.
 */
function convertOpenAIMessages(messages: ChatCompletionsPayload["messages"]): {
  anthropicMessages: Array<AnthropicMessage>
  systemPrompt?: string
} {
  const anthropicMessages: Array<AnthropicMessage> = []
  let systemPrompt: string | undefined

  for (const msg of messages) {
    switch (msg.role) {
      case "system":
      case "developer": {
        systemPrompt = typeof msg.content === "string" ? msg.content : ""

        break
      }
      case "user": {
        anthropicMessages.push({
          role: "user",
          content: typeof msg.content === "string" ? msg.content : "",
        })

        break
      }
      case "assistant": {
        anthropicMessages.push(convertAssistantMessage(msg))

        break
      }
      case "tool": {
        anthropicMessages.push({
          role: "user",
          content: [
            {
              type: "tool_result",
              tool_use_id: msg.tool_call_id ?? "",
              content: typeof msg.content === "string" ? msg.content : "",
            },
          ],
        } as unknown as AnthropicMessage)

        break
      }
      // No default
    }
  }

  return { anthropicMessages, systemPrompt }
}

/**
 * Convert OpenAI tool definitions to Anthropic format.
 */
function convertOpenAITools(
  tools: ChatCompletionsPayload["tools"],
): AnthropicMessagesPayload["tools"] {
  if (!tools) return undefined
  return tools.map((t) => ({
    name: t.function.name,
    description: t.function.description,
    input_schema: t.function.parameters,
  })) as AnthropicMessagesPayload["tools"]
}

/**
 * Convert OpenAI tool_choice to Anthropic format.
 */
function convertOpenAIToolChoice(
  choice: ChatCompletionsPayload["tool_choice"],
): AnthropicMessagesPayload["tool_choice"] {
  if (!choice) return undefined
  if (choice === "required") return { type: "any" }
  if (choice === "auto") return { type: "auto" }
  if (choice === "none") return { type: "none" }
  if (typeof choice === "object") {
    return { type: "tool", name: choice.function.name }
  }
  return undefined
}

/**
 * Convert an OpenAI Chat Completions payload to Anthropic Messages format.
 * Used when rerouting Claude models from /chat/completions to native /v1/messages.
 */
export function openaiToAnthropicPayload(
  payload: ChatCompletionsPayload,
): AnthropicMessagesPayload {
  const { anthropicMessages, systemPrompt } = convertOpenAIMessages(
    payload.messages,
  )

  const result: AnthropicMessagesPayload = {
    model: payload.model,
    messages: anthropicMessages,
    max_tokens: payload.max_tokens ?? 4096,
    stream: payload.stream ?? undefined,
  }

  if (systemPrompt) result.system = systemPrompt
  if (payload.temperature !== null && payload.temperature !== undefined)
    result.temperature = payload.temperature
  if (payload.top_p !== null && payload.top_p !== undefined)
    result.top_p = payload.top_p
  result.tools = convertOpenAITools(payload.tools)
  result.tool_choice = convertOpenAIToolChoice(payload.tool_choice)

  return result
}
